import{_ as a,o as i,c as t,ae as r}from"./chunks/framework.BD9pLfSD.js";const u=JSON.parse('{"title":"Branch Plan: Core Program + Credit State (Arcium)","description":"","frontmatter":{},"headers":[],"relativePath":"docs/plans/branch_core_program.md","filePath":"docs/plans/branch_core_program.md"}'),l={name:"docs/plans/branch_core_program.md"};function o(n,e,s,c,d,p){return i(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="branch-plan-core-program-credit-state-arcium" tabindex="-1">Branch Plan: Core Program + Credit State (Arcium) <a class="header-anchor" href="#branch-plan-core-program-credit-state-arcium" aria-label="Permalink to &quot;Branch Plan: Core Program + Credit State (Arcium)&quot;">​</a></h1><h2 id="objective" tabindex="-1">Objective <a class="header-anchor" href="#objective" aria-label="Permalink to &quot;Objective&quot;">​</a></h2><p>Create a new on-chain program that integrates with the existing programs and anchors the flow: verify identity, update encrypted credit state, and emit a payment request that the SDK can fulfill.</p><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><ul><li>New program scaffolding and instruction set (init, verify_and_credit, request_payment).</li><li>Integration points with existing programs (CPI or shared state contracts).</li><li>Explicit compatibility with <code>xb77_gateway</code> and <code>xb77_receipts</code>.</li><li>Define interface contracts that allow SDK flow: gateway -&gt; payment -&gt; receipt.</li><li>Arcium encrypted state model for agent credit lines (credit/debit).</li><li>Minimal Noir proof verification hook (can be stubbed if verifier integration is blocked).</li></ul><h2 id="out-of-scope" tabindex="-1">Out of Scope <a class="header-anchor" href="#out-of-scope" aria-label="Permalink to &quot;Out of Scope&quot;">​</a></h2><ul><li>ShadowWire or Privacy Cash SDK integration.</li><li>MCP server and client SDK orchestration.</li><li>UI or demo video.</li></ul><h2 id="milestones" tabindex="-1">Milestones <a class="header-anchor" href="#milestones" aria-label="Permalink to &quot;Milestones&quot;">​</a></h2><ol><li>Program skeleton and state layout finalized.</li><li>Credit line state update works (credit/debit).</li><li>Verify hook wired (real or stub) and request emitted.</li></ol><h2 id="integration-points" tabindex="-1">Integration Points <a class="header-anchor" href="#integration-points" aria-label="Permalink to &quot;Integration Points&quot;">​</a></h2><ul><li><code>xb77_gateway</code> (preferred CPI): new program exposes <code>verify_and_credit</code> and is invoked by gateway after proof validation.</li><li><code>xb77_gateway</code> (fallback client-side): SDK calls <code>verify_and_credit</code> directly after a successful gateway verify.</li><li><code>xb77_receipts</code> (preferred CPI): new program calls receipts on payment request.</li><li><code>xb77_receipts</code> (fallback client-side): SDK writes receipts when CPI is blocked.</li><li>Shared state: define PDA seeds so the new program can read/write credit line state without conflicting with existing PDAs.</li></ul><h2 id="interface-contract-v0-gateway-payment-receipt" tabindex="-1">Interface Contract v0 (gateway -&gt; payment -&gt; receipt) <a class="header-anchor" href="#interface-contract-v0-gateway-payment-receipt" aria-label="Permalink to &quot;Interface Contract v0 (gateway -&gt; payment -&gt; receipt)&quot;">​</a></h2><p><strong>payment_request</strong></p><ul><li>request_id (u64 or bytes32)</li><li>agent_id (pubkey or hash)</li><li>amount (u64)</li><li>currency (USD1/USDC/other enum)</li><li>vendor (pubkey or hash)</li><li>memo_hash (bytes32, optional)</li><li>proof_ref (bytes32)</li></ul><p><strong>payment_result</strong></p><ul><li>request_id</li><li>tx_sig</li><li>status (success/failed)</li><li>paid_amount</li><li>timestamp</li></ul><p><strong>receipt_payload</strong></p><ul><li>request_id</li><li>vendor</li><li>item_hash</li><li>amount</li><li>metadata_hash</li><li>payment_tx_sig</li></ul><p>Sequence:</p><ol><li>Gateway validates proof and emits payment_request.</li><li>SDK executes private payment (ShadowWire or Privacy Cash) and returns payment_result.</li><li>SDK writes receipt (Light or mock) using receipt_payload.</li></ol><h2 id="deliverables" tabindex="-1">Deliverables <a class="header-anchor" href="#deliverables" aria-label="Permalink to &quot;Deliverables&quot;">​</a></h2><ul><li>Program source + build scripts.</li><li>One local/devnet script to init and update credit state.</li><li>README snippet with commands.</li></ul><h2 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h2><ul><li>Arcium state SDK or schema definition.</li><li>Noir verifier address or stub interface.</li><li>Existing program interfaces (<code>xb77_gateway</code>, <code>xb77_receipts</code>).</li></ul><h2 id="risks" tabindex="-1">Risks <a class="header-anchor" href="#risks" aria-label="Permalink to &quot;Risks&quot;">​</a></h2><ul><li>Arcium API or encrypted state schema unclear.</li><li>CPI vs client-side update complexity.</li></ul><h2 id="fallback" tabindex="-1">Fallback <a class="header-anchor" href="#fallback" aria-label="Permalink to &quot;Fallback&quot;">​</a></h2><ul><li>Use a mock encrypted blob with deterministic hashing to preserve interface.</li></ul><h2 id="breakpoints" tabindex="-1">Breakpoints <a class="header-anchor" href="#breakpoints" aria-label="Permalink to &quot;Breakpoints&quot;">​</a></h2><ul><li>BP1: Program builds and deploys.</li><li>BP2: Credit state updates verified by script.</li><li>BP3: Payment request emitted and consumed by SDK.</li></ul>',30)])])}const m=a(l,[["render",o]]);export{u as __pageData,m as default};
